css:
.loader {
  color: var(--loader-color, #ec4899);
  --loader-secondary-color: #f9a8d4;
  --loader-bg: #ffffff;
width: 40px;
aspect-ratio: 1.154;
--_g: no-repeat radial-gradient(farthest-side,currentColor 90%,#0000);
background:
var(--_g) 50% 0,
var(--_g) 0 100%,
var(--_g) 100% 100%;
background-size: 35% calc(35%*1.154);
animation: l16 1s infinite;
}
@keyframes l16{
50%,100% {background-position: 100% 100%,50% 0,0 100%}
}
